  6→package kotlinx.datetime
  7→
  8→import kotlinx.datetime.format.*
  9→import kotlinx.datetime.internal.JSJoda.Instant as jtInstant
 10→import kotlinx.datetime.internal.JSJoda.OffsetDateTime as jtOffsetDateTime
 11→import kotlinx.datetime.internal.JSJoda.Duration as jtDuration
 12→import kotlinx.datetime.internal.JSJoda.Clock as jtClock
 13→import kotlinx.datetime.internal.JSJoda.ChronoUnit as jtChronoUnit
 14→import kotlinx.datetime.internal.JSJoda.ZonedDateTime as jtZonedDateTime
 15→import kotlinx.datetime.internal.safeAdd
 16→import kotlinx.datetime.internal.*
 17→import kotlinx.datetime.serializers.InstantIso8601Serializer
 18→import kotlinx.serialization.Serializable
 19→import kotlin.time.*
 20→import kotlin.time.Duration.Companion.nanoseconds
 21→import kotlin.time.Duration.Companion.seconds
 22→
 23→@Serializable(with = InstantIso8601Serializer::class)
 24→public actual class Instant internal constructor(internal val value: jtInstant) : Comparable<Instant> {
 25→
 26→    public actual val epochSeconds: Long
 27→        get() = value.epochSecond().toLong()
 28→    public actual val nanosecondsOfSecond: Int
 29→        get() = value.nano().toInt()
 30→
 31→    public actual fun toEpochMilliseconds(): Long =
 32→            epochSeconds * MILLIS_PER_ONE + nanosecondsOfSecond / NANOS_PER_MILLI
 33→
 34→    public actual operator fun plus(duration: Duration): Instant = duration.toComponents { seconds, nanoseconds ->
 35→        return try {
 36→            Instant(plusFix(seconds.toDouble(), nanoseconds))
 37→        } catch (e: Throwable) {
 38→            if (!e.isJodaDateTimeException()) throw e
 39→            if (duration.isPositive()) MAX else MIN
 40→        }
 41→    }
 42→
 43→    internal fun plusFix(seconds: Double, nanos: Int): jtInstant {
 44→        val newSeconds = value.epochSecond() + seconds
 45→        val newNanos = value.nano() + nanos
 46→        return jsTry { jtInstant.ofEpochSecond(newSeconds, newNanos.toInt()) }
 47→    }
 48→
 49→    public actual operator fun minus(duration: Duration): Instant = plus(-duration)
 50→
 51→    public actual operator fun minus(other: Instant): Duration {
 52→        val diff = jtDuration.between(other.value, this.value)
 53→        return diff.seconds().seconds + diff.nano().nanoseconds
 54→    }
 55→
 56→    public actual override operator fun compareTo(other: Instant): Int = this.value.compareTo(other.value)
 57→
 58→    override fun equals(other: Any?): Boolean =
 59→            (this === other) || (other is Instant && (this.value === other.value || this.value.equals(other.value)))
 60→
 61→    override fun hashCode(): Int = value.hashCode()
 62→
 63→    actual override fun toString(): String = value.toString()
 64→
 65→    public actual companion object {
 66→        @Deprecated("Use Clock.System.now() instead", ReplaceWith("Clock.System.now()", "kotlinx.datetime.Clock"), level = DeprecationLevel.ERROR)
 67→        public actual fun now(): Instant =
 68→                Instant(jtClock.systemUTC().instant())
 69→
 70→        public actual fun fromEpochMilliseconds(epochMilliseconds: Long): Instant = try {
 71→            fromEpochSeconds(epochMilliseconds / MILLIS_PER_ONE, epochMilliseconds % MILLIS_PER_ONE * NANOS_PER_MILLI)
 72→        } catch (e: Throwable) {
 73→            if (!e.isJodaDateTimeException()) throw e
 74→            if (epochMilliseconds > 0) MAX else MIN
 75→        }
 76→
 77→        public actual fun parse(input: CharSequence, format: DateTimeFormat<DateTimeComponents>): Instant =
 78→            if (format === DateTimeComponents.Formats.ISO_DATE_TIME_OFFSET) {
 79→                try {
 80→                    Instant(jsTry { jtOffsetDateTime.parse(fixOffsetRepresentation(input.toString())) }.toInstant())
 81→                } catch (e: Throwable) {
 82→                    if (e.isJodaDateTimeParseException()) throw DateTimeFormatException(e)
 83→                    throw e
 84→                }
 85→            } else {
 86→                try {
 87→                    format.parse(input).toInstantUsingOffset()
 88→                } catch (e: IllegalArgumentException) {
 89→                    throw DateTimeFormatException("Failed to parse an instant from '$input'", e)
 90→                }
 91→            }
 92→
 93→        @Deprecated("This overload is only kept for binary compatibility", level = DeprecationLevel.HIDDEN)
 94→        public fun parse(isoString: String): Instant = parse(input = isoString)
 95→
 96→        /** A workaround for the string representations of Instant that have an offset of the form
 97→         * "+XX" not being recognized by [jtOffsetDateTime.parse], while "+XX:XX" work fine. */
 98→        private fun fixOffsetRepresentation(isoString: String): String {
 99→            val time = isoString.indexOf('T', ignoreCase = true)
100→            if (time == -1) return isoString // the string is malformed
101→            val offset = isoString.indexOfLast { c -> c == '+' || c == '-' }
102→            if (offset < time) return isoString // the offset is 'Z' and not +/- something else
103→            val separator = isoString.indexOf(':', offset) // if there is a ':' in the offset, no changes needed
104→            return if (separator != -1) isoString else "$isoString:00"
105→        }
106→
107→        public actual fun fromEpochSeconds(epochSeconds: Long, nanosecondAdjustment: Long): Instant = try {
108→            /* Performing normalization here because otherwise this fails:
109→               assertEquals((Long.MAX_VALUE % 1_000_000_000).toInt(),
110→                            Instant.fromEpochSeconds(0, Long.MAX_VALUE).nanosecondsOfSecond) */
111→            val secs = safeAdd(epochSeconds, nanosecondAdjustment.floorDiv(NANOS_PER_ONE.toLong()))
112→            val nos = nanosecondAdjustment.mod(NANOS_PER_ONE.toLong()).toInt()
113→            Instant(jsTry { jtInstant.ofEpochSecond(secs.toDouble(), nos) })
114→        } catch (e: Throwable) {
115→            if (!e.isJodaDateTimeException() && e !is ArithmeticException) throw e
116→            if (epochSeconds > 0) MAX else MIN
117→        }
118→
119→        public actual fun fromEpochSeconds(epochSeconds: Long, nanosecondAdjustment: Int): Instant = try {
120→            Instant(jsTry { jtInstant.ofEpochSecond(epochSeconds.toDouble(), nanosecondAdjustment) })
121→        } catch (e: Throwable) {
122→            if (!e.isJodaDateTimeException()) throw e
123→            if (epochSeconds > 0) MAX else MIN
124→        }
125→
126→        public actual val DISTANT_PAST: Instant = Instant(jsTry { jtInstant.ofEpochSecond(DISTANT_PAST_SECONDS.toDouble(), 999_999_999) })
127→        public actual val DISTANT_FUTURE: Instant = Instant(jsTry { jtInstant.ofEpochSecond(DISTANT_FUTURE_SECONDS.toDouble(), 0) })
128→
129→        internal actual val MIN: Instant = Instant(jtInstant.MIN)
130→        internal actual val MAX: Instant = Instant(jtInstant.MAX)
131→    }
132→}
133→
134→
135→public actual fun Instant.plus(period: DateTimePeriod, timeZone: TimeZone): Instant = try {
136→    val thisZdt = jsTry { this.value.atZone(timeZone.zoneId) }
137→    with(period) {
138→        thisZdt
139→                .run { if (totalMonths != 0) jsTry { plusMonths(totalMonths) } else this }
140→                .run { if (days != 0) jsTry { plusDays(days) } else this }
141→                .run { if (hours != 0) jsTry { plusHours(hours) } else this }
142→                .run { if (minutes != 0) jsTry { plusMinutes(minutes) } else this }
143→                .run { if (seconds != 0) jsTry { plusSeconds(seconds) } else this }
144→                .run { if (nanoseconds != 0) jsTry { plusNanos(nanoseconds.toDouble()) } else this }
145→    }.toInstant().let(::Instant)
146→}    catch (e: Throwable) {
147→    if (e.isJodaDateTimeException()) throw DateTimeArithmeticException(e)
148→    throw e
149→}
150→
151→private fun Instant.atZone(zone: TimeZone): jtZonedDateTime = jsTry { value.atZone(zone.zoneId) }
152→private fun jtInstant.checkZone(zone: TimeZone): jtInstant = apply { jsTry { atZone(zone.zoneId) } }
153→
154→@Deprecated("Use the plus overload with an explicit number of units", ReplaceWith("this.plus(1, unit, timeZone)"))
155→public actual fun Instant.plus(unit: DateTimeUnit, timeZone: TimeZone): Instant =
156→        plus(1, unit, timeZone)
157→
158→public actual fun Instant.plus(value: Long, unit: DateTimeUnit, timeZone: TimeZone): Instant =
159→        try {
160→            val thisZdt = this.atZone(timeZone)
161→            when (unit) {
162→                is DateTimeUnit.TimeBased -> {
163→                    plus(value, unit).value.checkZone(timeZone)
164→                }
165→                is DateTimeUnit.DayBased ->
166→                    jsTry {thisZdt.plusDays(value.toDouble() * unit.days) }.toInstant()
167→                is DateTimeUnit.MonthBased ->
168→                    jsTry { thisZdt.plusMonths(value.toDouble() * unit.months) }.toInstant()
169→            }.let(::Instant)
170→        } catch (e: Throwable) {
171→            if (e.isJodaDateTimeException()) throw DateTimeArithmeticException(e)
172→            throw e
173→        }
174→
175→public actual fun Instant.plus(value: Int, unit: DateTimeUnit, timeZone: TimeZone): Instant =
176→        try {
177→            val thisZdt = this.atZone(timeZone)
178→            when (unit) {
179→                is DateTimeUnit.TimeBased ->
180→                    plus(value.toLong(), unit).value.checkZone(timeZone)
181→                is DateTimeUnit.DayBased ->
182→                    jsTry { thisZdt.plusDays(value.toDouble() * unit.days) }.toInstant()
183→                is DateTimeUnit.MonthBased ->
184→                    jsTry { thisZdt.plusMonths(value.toDouble() * unit.months) }.toInstant()
185→            }.let(::Instant)
186→        } catch (e: Throwable) {
187→            if (e.isJodaDateTimeException()) throw DateTimeArithmeticException(e)
188→            throw e
189→        }
190→
191→public actual fun Instant.minus(value: Int, unit: DateTimeUnit, timeZone: TimeZone): Instant =
192→    if (value == Int.MIN_VALUE)
193→        plus(-value.toLong(), unit, timeZone)
194→    else
195→        plus(-value, unit, timeZone)
196→
197→public actual fun Instant.plus(value: Long, unit: DateTimeUnit.TimeBased): Instant =
198→    try {
199→        multiplyAndDivide(value, unit.nanoseconds, NANOS_PER_ONE.toLong()).let { (d, r) ->
200→            Instant(plusFix(d.toDouble(), r.toInt()))
201→        }
202→    } catch (e: Throwable) {
203→        if (!e.isJodaDateTimeException()) {
204→            throw e
205→        }
206→        if (value > 0) Instant.MAX else Instant.MIN
207→    }
208→
209→public actual fun Instant.periodUntil(other: Instant, timeZone: TimeZone): DateTimePeriod = try {
210→    var thisZdt = jsTry { this.value.atZone(timeZone.zoneId) }
211→    val otherZdt = jsTry { other.value.atZone(timeZone.zoneId) }
212→
213→    val months = thisZdt.until(otherZdt, jtChronoUnit.MONTHS); thisZdt = jsTry { thisZdt.plusMonths(months) }
214→    val days = thisZdt.until(otherZdt, jtChronoUnit.DAYS); thisZdt = jsTry { thisZdt.plusDays(days) }
215→    val nanoseconds = thisZdt.until(otherZdt, jtChronoUnit.NANOS)
216→
217→    buildDateTimePeriod(months.toInt(), days.toInt(), nanoseconds.toLong())
218→} catch (e: Throwable) {
219→    if (e.isJodaDateTimeException()) throw DateTimeArithmeticException(e) else throw e
220→}
221→
222→public actual fun Instant.until(other: Instant, unit: DateTimeUnit, timeZone: TimeZone): Long = try {
223→    val thisZdt = this.atZone(timeZone)
224→    val otherZdt = other.atZone(timeZone)
225→    when(unit) {
226→        is DateTimeUnit.TimeBased -> until(other, unit)
227→        is DateTimeUnit.DayBased -> (thisZdt.until(otherZdt, jtChronoUnit.DAYS) / unit.days).toLong()
228→        is DateTimeUnit.MonthBased -> (thisZdt.until(otherZdt, jtChronoUnit.MONTHS) / unit.months).toLong()
229→    }
230→} catch (e: ArithmeticException) {
231→    if (this < other) Long.MAX_VALUE else Long.MIN_VALUE
232→} catch (e: Throwable) {
233→    if (e.isJodaDateTimeException()) throw DateTimeArithmeticException(e) else throw e
234→}
