232→internal class CachedFormatStructure<in T>(formats: List<NonConcatenatedFormatStructure<T>>) :
233→    ConcatenatedFormatStructure<T>(formats) {
234→    private val cachedFormatter: FormatterStructure<T> by lazy { super.formatter() }
235→    private val cachedParser: ParserStructure<T> by lazy { super.parser() }
236→
237→    override fun formatter(): FormatterStructure<T> = cachedFormatter
238→
239→    override fun parser(): ParserStructure<T> = cachedParser
240→}
