149→    @Test
150→    fun unitsUntil() {
151→        val data = listOf(
152→                Pair(Pair("2012-06-30", "2012-06-30"), Pair(DateTimeUnit.DAY, 0)),
153→                Pair(Pair("2012-06-30", "2012-06-30"), Pair(DateTimeUnit.WEEK, 0)),
154→                Pair(Pair("2012-06-30", "2012-06-30"), Pair(DateTimeUnit.MONTH, 0)),
155→                Pair(Pair("2012-06-30", "2012-06-30"), Pair(DateTimeUnit.YEAR, 0)),
156→                Pair(Pair("2012-06-30", "2012-07-01"), Pair(DateTimeUnit.DAY, 1)),
157→                Pair(Pair("2012-06-30", "2012-07-01"), Pair(DateTimeUnit.WEEK, 0)),
158→                Pair(Pair("2012-06-30", "2012-07-01"), Pair(DateTimeUnit.MONTH, 0)),
159→                Pair(Pair("2012-06-30", "2012-07-01"), Pair(DateTimeUnit.YEAR, 0)),
160→                Pair(Pair("2012-06-30", "2012-07-07"), Pair(DateTimeUnit.DAY, 7)),
161→                Pair(Pair("2012-06-30", "2012-07-07"), Pair(DateTimeUnit.WEEK, 1)),
162→                Pair(Pair("2012-06-30", "2012-07-07"), Pair(DateTimeUnit.MONTH, 0)),
163→                Pair(Pair("2012-06-30", "2012-07-07"), Pair(DateTimeUnit.YEAR, 0)),
164→                Pair(Pair("2012-06-30", "2012-07-29"), Pair(DateTimeUnit.MONTH, 0)),
165→                Pair(Pair("2012-06-30", "2012-07-30"), Pair(DateTimeUnit.MONTH, 1)),
166→                Pair(Pair("2012-06-30", "2012-07-31"), Pair(DateTimeUnit.MONTH, 1)))
167→        for ((values, interval) in data) {
168→            val (v1, v2) = values
169→            val (unit, length) = interval
170→            val start = LocalDate.parse(v1)
171→            val end = LocalDate.parse(v2)
172→            assertEquals(length, start.until(end, unit), "$v2 - $v1 = $length($unit)")
173→            assertEquals(-length, end.until(start, unit), "$v1 - $v2 = -$length($unit)")
174→            when (unit) {
175→                DateTimeUnit.YEAR -> assertEquals(length, start.yearsUntil(end))
176→                DateTimeUnit.MONTH -> assertEquals(length, start.monthsUntil(end))
177→                DateTimeUnit.WEEK -> assertEquals(length, start.daysUntil(end) / 7)
178→                DateTimeUnit.DAY -> assertEquals(length, start.daysUntil(end))
179→                else -> error(unit)
180→            }
181→        }
182→
183→    }
