  6→package kotlinx.datetime.internal.format
  7→
  8→import kotlinx.datetime.internal.format.formatter.*
  9→import kotlinx.datetime.internal.format.parser.*
 10→
 11→internal sealed interface FormatStructure<in T> {
 12→    fun parser(): ParserStructure<T>
 13→    fun formatter(): FormatterStructure<T>
 14→}
 15→
 16→internal class BasicFormatStructure<in T>(
 17→    val directive: FieldFormatDirective<T>
 18→) : NonConcatenatedFormatStructure<T> {
 19→    override fun toString(): String = "BasicFormatStructure($directive)"
 20→
 21→    override fun equals(other: Any?): Boolean = other is BasicFormatStructure<*> && directive == other.directive
 22→    override fun hashCode(): Int = directive.hashCode()
 23→
 24→    override fun parser(): ParserStructure<T> = directive.parser()
 25→    override fun formatter(): FormatterStructure<T> = directive.formatter()
 26→}
 27→
 28→internal class ConstantFormatStructure<in T>(
 29→    val string: String
 30→) : NonConcatenatedFormatStructure<T> {
 31→    override fun toString(): String = "ConstantFormatStructure($string)"
 32→
 33→    override fun equals(other: Any?): Boolean = other is ConstantFormatStructure<*> && string == other.string
 34→    override fun hashCode(): Int = string.hashCode()
 35→
 36→    override fun parser(): ParserStructure<T> = ParserStructure(
 37→        operations = when {
 38→            string.isEmpty() -> emptyList()
 39→            else -> buildList {
 40→                val suffix = if (string[0].isDigit()) {
 41→                    add(NumberSpanParserOperation(listOf(ConstantNumberConsumer(string.takeWhile { it.isDigit() }))))
 42→                    string.dropWhile { it.isDigit() }
 43→                } else {
 44→                    string
 45→                }
 46→                if (suffix.isNotEmpty()) {
 47→                    if (suffix[suffix.length - 1].isDigit()) {
 48→                        add(PlainStringParserOperation(suffix.dropLastWhile { it.isDigit() }))
 49→                        add(NumberSpanParserOperation(listOf(ConstantNumberConsumer(suffix.takeLastWhile { it.isDigit() }))))
 50→                    } else {
 51→                        add(PlainStringParserOperation(suffix))
 52→                    }
 53→                }
 54→            }
 55→        },
 56→        followedBy = emptyList()
 57→    )
 58→
 59→    override fun formatter(): FormatterStructure<T> = ConstantStringFormatterStructure(string)
 60→}
 61→
 62→internal class SignedFormatStructure<in T>(
 63→    val format: FormatStructure<T>,
 64→    val withPlusSign: Boolean,
 65→) : NonConcatenatedFormatStructure<T> {
 66→
 67→    private val fieldSigns = basicFormats(format).mapNotNull { it.field.sign }.toSet()
 68→
 69→    init {
 70→        require(fieldSigns.isNotEmpty()) { "Signed format must contain at least one field with a sign" }
 71→    }
 72→
 73→    override fun toString(): String = "SignedFormatStructure($format)"
 74→
 75→    override fun equals(other: Any?): Boolean =
 76→        other is SignedFormatStructure<*> && format == other.format && withPlusSign == other.withPlusSign
 77→
 78→    override fun hashCode(): Int = 31 * format.hashCode() + withPlusSign.hashCode()
 79→
 80→    override fun parser(): ParserStructure<T> = listOf(
 81→        ParserStructure(
 82→            operations = listOf(
 83→                SignParser(
 84→                    isNegativeSetter = { value, isNegative ->
 85→                        for (field in fieldSigns) {
 86→                            val wasNegative = field.isNegative.getter(value) == true
 87→                            // TODO: replacing `!=` with `xor` fails on JS
 88→                            field.isNegative.trySetWithoutReassigning(value, isNegative != wasNegative)
 89→                        }
 90→                    },
 91→                    withPlusSign = withPlusSign,
 92→                    whatThisExpects = "sign for ${this.fieldSigns}"
 93→                )
 94→            ),
 95→            emptyList()
 96→        ), format.parser()
 97→    ).concat()
 98→
 99→    override fun formatter(): FormatterStructure<T> {
100→        val innerFormat = format.formatter()
101→        fun checkIfAllNegative(value: T): Boolean {
102→            var seenNonZero = false
103→            for (check in fieldSigns) {
104→                when {
105→                    check.isNegative.getter(value) == true -> seenNonZero = true
106→                    check.isZero(value) -> continue
107→                    else -> return false
108→                }
109→            }
110→            return seenNonZero
111→        }
112→        return SignedFormatter(
113→            innerFormat,
114→            ::checkIfAllNegative,
115→            withPlusSign
116→        )
117→    }
118→}
119→
120→internal class AlternativesParsingFormatStructure<in T>(
121→    val mainFormat: FormatStructure<T>,
122→    val formats: List<FormatStructure<T>>,
123→) : NonConcatenatedFormatStructure<T> {
124→    override fun toString(): String = "AlternativesParsing($formats)"
125→
126→    override fun equals(other: Any?): Boolean =
127→        other is AlternativesParsingFormatStructure<*> && mainFormat == other.mainFormat && formats == other.formats
128→
129→    override fun hashCode(): Int = 31 * mainFormat.hashCode() + formats.hashCode()
130→
131→    override fun parser(): ParserStructure<T> = ParserStructure(operations = emptyList(), followedBy = buildList {
132→        add(mainFormat.parser())
133→        for (format in formats) {
134→            add(format.parser())
135→        }
136→    })
137→
138→    override fun formatter(): FormatterStructure<T> = mainFormat.formatter()
139→}
140→
141→internal class OptionalFormatStructure<in T>(
142→    val onZero: String,
143→    val format: FormatStructure<T>,
144→) : NonConcatenatedFormatStructure<T> {
145→    override fun toString(): String = "Optional($onZero, $format)"
146→
147→    private val fields = basicFormats(format).map { it.field }.distinct().map { field ->
148→        PropertyWithDefault.fromField(field)
149→    }
150→
151→    override fun equals(other: Any?): Boolean =
152→        other is OptionalFormatStructure<*> && onZero == other.onZero && format == other.format
153→
154→    override fun hashCode(): Int = 31 * onZero.hashCode() + format.hashCode()
155→
156→    override fun parser(): ParserStructure<T> = ParserStructure(
157→        operations = emptyList(),
158→        followedBy = listOf(
159→            format.parser(),
160→            listOf(
161→                ConstantFormatStructure<T>(onZero).parser(),
162→                ParserStructure(
163→                    if (fields.isEmpty()) {
164→                        emptyList()
165→                    } else {
166→                        listOf(
167→                            UnconditionalModification {
168→                                for (field in fields) {
169→                                    field.assignDefault(it)
170→                                }
171→                            }
172→                        )
173→                    },
174→                    emptyList()
175→                )
176→            ).concat()
177→        )
178→    )
179→
180→    override fun formatter(): FormatterStructure<T> {
181→        val formatter = format.formatter()
182→        val predicate = conjunctionPredicate(fields.map { it.isDefaultComparisonPredicate() })
183→        return if (predicate is Truth) {
184→            ConstantStringFormatterStructure(onZero)
185→        } else {
186→            ConditionalFormatter(
187→                listOf(
188→                    predicate::test to ConstantStringFormatterStructure(onZero),
189→                    Truth::test to formatter
190→                )
191→            )
192→        }
193→    }
194→
195→    private class PropertyWithDefault<in T, E> private constructor(
196→        private val accessor: Accessor<T, E>,
197→        private val defaultValue: E
198→    ) {
199→        companion object {
200→            fun <T, E> fromField(field: FieldSpec<T, E>): PropertyWithDefault<T, E> {
201→                val default = field.defaultValue
202→                require(default != null) {
203→                    "The field '${field.name}' does not define a default value"
204→                }
205→                return PropertyWithDefault(field.accessor, default)
206→            }
207→        }
208→
209→        inline fun assignDefault(target: T) {
210→            accessor.trySetWithoutReassigning(target, defaultValue)
211→        }
212→
213→        inline fun isDefaultComparisonPredicate() = ComparisonPredicate(defaultValue, accessor::getter)
214→    }
215→}
216→
217→internal sealed interface NonConcatenatedFormatStructure<in T> : FormatStructure<T>
218→
219→internal open class ConcatenatedFormatStructure<in T>(
220→    val formats: List<NonConcatenatedFormatStructure<T>>
221→) : FormatStructure<T> {
222→    override fun toString(): String = "ConcatenatedFormatStructure(${formats.joinToString(", ")})"
223→
224→    override fun equals(other: Any?): Boolean = other is ConcatenatedFormatStructure<*> && formats == other.formats
225→
226→    override fun hashCode(): Int = formats.hashCode()
227→
228→    override fun parser(): ParserStructure<T> = formats.map { it.parser() }.concat()
229→
230→    override fun formatter(): FormatterStructure<T> {
231→        val formatters = formats.map { it.formatter() }
232→        return if (formatters.size == 1) {
233→            formatters.single()
234→        } else {
235→            ConcatenatedFormatter(formatters)
236→        }
237→    }
238→}
239→
240→internal class CachedFormatStructure<in T>(formats: List<NonConcatenatedFormatStructure<T>>) :
241→    ConcatenatedFormatStructure<T>(formats) {
242→    private val cachedFormatter: FormatterStructure<T> = super.formatter()
243→    private val cachedParser: ParserStructure<T> = super.parser()
244→
245→    override fun formatter(): FormatterStructure<T> = cachedFormatter
246→
247→    override fun parser(): ParserStructure<T> = cachedParser
248→}
249→
250→private fun <T> basicFormats(format: FormatStructure<T>): List<FieldFormatDirective<T>> = buildList {
251→    fun rec(format: FormatStructure<T>) {
252→        when (format) {
253→            is BasicFormatStructure -> add(format.directive)
254→            is ConcatenatedFormatStructure -> format.formats.forEach { rec(it) }
255→            is ConstantFormatStructure -> {}
256→            is SignedFormatStructure -> rec(format.format)
257→            is AlternativesParsingFormatStructure -> {
258→                rec(format.mainFormat); format.formats.forEach { rec(it) }
259→            }
260→
261→            is OptionalFormatStructure -> rec(format.format)
262→        }
263→    }
264→    rec(format)
265→}
